export class JsonSchemaParseContext {
	readonly defs: Record<string, JsonSchemaOrBoolean>
	private readonly resolvedRefs = new Map<string, type.Any>()

	constructor(root: JsonSchemaOrBoolean) {
		this.defs =
			typeof root === "object" && root !== null && !Array.isArray(root) ?
				(root.$defs ?? {})
			: {}
	}

	parse(jsonSchema: JsonSchemaOrBoolean): type.Any {
		return parseJsonSchema(jsonSchema, this)
	}

	resolveRef(ref: string): type.Any {
		const prefix = "#/$defs/"
		if (!ref.startsWith(prefix) || ref.length === prefix.length)
			throwParseError("Only local $ref values of the form #/$defs/<name> are supported")
		const name = ref.slice(prefix.length)
		if (!(name in this.defs))
			throwParseError(`Unable to resolve $ref \"${ref}\" from root $defs`)
		const existing = this.resolvedRefs.get(name)
		if (existing) return existing

		// A thunk gives recursive definitions an alias which is only resolved when
		// traversed. Storing it before parsing the definition breaks self cycles.
		const resolved = type(() => this.parse(this.defs[name]))
		this.resolvedRefs.set(name, resolved)
		return resolved
	}
}

export const parseJsonSchema = (
	jsonSchema: JsonSchemaOrBoolean,
	context: JsonSchemaParseContext = new JsonSchemaParseContext(jsonSchema)
): type.Any => {
		if (typeof jsonSchema === "boolean")
			// no runtime value ever passes validation for JSON schema of 'false'
			return jsonSchema ? JsonSchemaScope.Json : type.never

		if (Array.isArray(jsonSchema)) return parseAnyOfJsonSchema(jsonSchema, context)

		if ("$ref" in jsonSchema) return context.resolveRef(jsonSchema.$ref)

		const constAndOrEnumValidator = parseCommonJsonSchema(
			jsonSchema as JsonSchema
		)
		const compositionValidator = parseCompositionJsonSchema(
			jsonSchema as JsonSchema,
			context
		)

		const preTypeValidator =
			constAndOrEnumValidator ?
				compositionValidator ? compositionValidator.and(constAndOrEnumValidator)
				:	constAndOrEnumValidator
			:	compositionValidator

		const hasObjectKeywords = [
			"properties",
			"required",
			"patternProperties",
			"additionalProperties",
			"maxProperties",
			"minProperties",
			"propertyNames",
			"dependencies",
			"dependentRequired",
			"dependentSchemas"
		].some(key => key in jsonSchema)

		if ("type" in jsonSchema || hasObjectKeywords) {
			const typeValidator = jsonSchemaTypeMatcher(jsonSchema as never) as
				| type.Any
				| undefined
			const implicitObjectValidator = hasObjectKeywords ?
				parseObjectJsonSchema.assert({ ...jsonSchema, type: "object" }, context)
			: undefined

			if (typeValidator === undefined && implicitObjectValidator === undefined) {
				throwParseError(
					writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchema.type))
				)
			}

			const validator = typeValidator ?? implicitObjectValidator!
			if (preTypeValidator === undefined) return validator
			return validator.and(preTypeValidator)
		}
		if (preTypeValidator === undefined) {
			const atLeastOneOf = [
				"'type'",
				"'enum'",
				"'const'",
				"'allOf'",
				"'anyOf'",
				"'oneOf'",
				"'not'"
			]
			throwParseError(
				writeJsonSchemaInsufficientKeysMessage(
					describeBranches(atLeastOneOf, { finalDelimiter: " and " }),
					printable(jsonSchema)
				)
			)
		}
		return preTypeValidator
	}

